-- Query: qSessionReport1
SELECT Customers.SchoolID, IIf([Sessions].[CustomerID]<99999999,Int([Sessions].[CustomerID]/1000)*1000,Int(Val(Mid$(Trim$(Str([Sessions].[CustomerID])),5))/1000)*1000) AS SchoolIDOld, Sessions.*, Customers.CustomerID, Customers.LastName, Customers.FirstName, Customers.S_LastName, Customers.S_FirstName, Customers.Gender, Customers.Address, Customers.City, Customers.State, Customers.ZipCode, Customers.Phone, Customers.Photographed, Customers.Deleted, Customers.DateDeleted, Customers.DeletedBy, Customers.Season, Customers.CurrentStatus, Customers.Update, Customers.Notes, Customers.EMail, Customers.Misc1, Customers.Misc2, Customers.Misc3, Customers.StudentID, Customers.CoCustomerID, Customers.WebPassword, Customers.Log, Customers.PrintedIDs, Customers.OverlayText, Customers.Retake, Customers.EMail2, Customers.Address2, Customers.City2, Customers.State2, Customers.ZipCode2, Customers.ProofBookFrontSession, Customers.ProofBookFrontPose, Customers.ProofBookBackSession, Customers.ProofBookBackPose, Customers.MobilePhone1, Customers.MobilePhone2, Customers.LastUpdateUser, Customers.LastUpdateDate, Customers.LastImportDate
FROM Sessions INNER JOIN Customers ON Sessions.CustomerID = Customers.CustomerID;

